const body = $json.body ?? $json;

if (body.event !== 'paper.submitted') {
  throw new Error(`Unsupported Peerflow event: ${body.event ?? 'missing'}`);
}

if (!body.paper?.id) {
  throw new Error('Peerflow payload is missing paper.id');
}

return [
  {
    json: {
      event: body.event,
      eventId: body.eventId ?? body.runId,
      runId: body.runId ?? body.eventId,
      occurredAt: body.occurredAt,
      source: body.source ?? 'Peerflow',
      paper: body.paper,
      attioRecords: body.attioRecords ?? {},
      attioTargets: body.attioTargets ?? {},
      backend: body.orchestration?.backend ?? {},
      requiredActions: body.orchestration?.requiredActions ?? [],
      orchestrationContract: body.orchestration?.contract ?? [],
      currentStage: body.orchestration?.currentStage ?? body.paper.stage ?? 'Submitted',
      targetStage: body.orchestration?.targetStage ?? body.paper.targetStage ?? 'Reviewer matched'
    }
  }
];

const input = $json;
const institution = input.attioRecords.institution ?? {};
const author = input.attioRecords.author ?? {};
const paper = input.paper ?? {};
const followUpTask = input.attioRecords.followUpTask ?? {};

function slugify(value) {
  return String(value ?? 'peerflow')
    .toLowerCase()
    .replace(/[^a-z0-9]+/g, '-')
    .replace(/(^-|-$)/g, '')
    .slice(0, 64) || 'peerflow';
}

const institutionDomain = institution.domain ?? `${slugify(institution.name ?? paper.institution ?? paper.id)}-peerflow.dev`;
const authorEmail = author.email ?? `${slugify(author.name ?? paper.author ?? paper.id)}.${paper.id}@example.com`;

return [
  {
    json: {
      ...input,
      attioTargets: {
        authorObject: input.attioTargets.authorObject ?? 'people',
        authorMatchingAttribute: input.attioTargets.authorMatchingAttribute ?? 'email_addresses',
        institutionObject: input.attioTargets.institutionObject ?? 'companies',
        institutionMatchingAttribute: input.attioTargets.institutionMatchingAttribute ?? 'domains',
        paperStage: input.attioTargets.paperStage ?? input.targetStage
      },
      attioInstitutionPayload: {
        data: {
          values: {
            name: institution.name ?? paper.institution,
            domains: [institutionDomain],
            description: `Peerflow demo institution for ${paper.title}`
          }
        }
      },
      attioAuthorPayload: {
        data: {
          values: {
            name: author.name ?? paper.author,
            email_addresses: [authorEmail],
            description: `Peerflow demo author for ${paper.title}. Field: ${paper.field}. Target stage: ${input.targetStage}`
          }
        }
      },
      attioTaskPayload: {
        data: {
          content: [
            `Peerflow reviewer outreach: ${paper.title}`,
            `Author: ${author.name ?? paper.author}`,
            `Institution: ${institution.name ?? paper.institution}`,
            `Field: ${paper.field}`,
            `Stage: ${input.targetStage}`,
            'Next step: contact top reviewer candidates and log response.'
          ].join('\n'),
          format: 'plaintext',
          deadline_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
          is_completed: false,
          assignees: [],
          linked_records: []
        }
      },
      reviewerMatchRequest: input.backend.reviewerMatches ?? {
        method: 'POST',
        url: '',
        body: {
          paperId: paper.id,
          embeddingModel: 'sentence-transformers/all-MiniLM-L6-v2',
          rerankModel: 'cross-encoder/ms-marco-MiniLM-L-6-v2'
        },
        reachableFromN8nCloud: false
      },
      outreachTask: {
        title: followUpTask.title ?? `Review outreach for ${paper.title}`,
        status: followUpTask.status ?? 'open',
        owner: followUpTask.owner ?? 'Editorial desk',
        paperId: paper.id,
        stage: input.targetStage
      }
    }
  }
];

const source = $('Build orchestration payloads').first().json;
let reviewerMatches = [];
let reviewerSource = 'Reviewer matching response unavailable';
let attioTaskId = null;
let attioTaskSource = 'Attio task creation not confirmed';

try {
  const matchTask = $('Build Attio task with reviewer matches').first().json;
  reviewerMatches = Array.isArray(matchTask.reviewerMatching?.matches) ? matchTask.reviewerMatching.matches : [];
  reviewerSource = matchTask.reviewerMatching?.source ?? reviewerSource;
} catch (error) {
  reviewerSource = String(error.message ?? error);
}

try {
  const taskResponse = $('Attio create outreach task').first().json;
  attioTaskId = taskResponse.data?.id?.task_id ?? null;
  attioTaskSource = attioTaskId ? 'Attio task created with reviewer matches' : 'Attio task request attempted';
} catch (error) {
  attioTaskSource = String(error.message ?? error);
}

return [
  {
    json: {
      mode: 'live',
      event: source.event,
      runId: source.runId,
      orchestrationOwner: 'n8n',
      orchestrationContract: source.orchestrationContract,
      nextStage: source.targetStage,
      paper: {
        id: source.paper.id,
        title: source.paper.title,
        stage: source.targetStage
      },
      attio: {
        institutionUpsert: 'attempted',
        authorUpsert: 'attempted',
        outreachTask: attioTaskSource,
        outreachTaskId: attioTaskId,
        reviewerMatchesPushed: reviewerMatches.length,
        variableRequired: 'ATTIO_API_KEY'
      },
      reviewerMatching: {
        method: 'Superlinked semantic embedding plus reranking, not keyword search',
        source: reviewerSource,
        profileInputs: 'paper title + abstract + field vs reviewer expertise + institution + past review topics',
        embeddingModel: 'all-MiniLM-L6-v2',
        rerankModel: 'ms-marco-MiniLM-L-6-v2',
        matches: reviewerMatches.slice(0, 3)
      },
      outreachTask: {
        ...source.outreachTask,
        createdBy: 'n8n workflow'
      },
      stageUpdate: {
        from: source.currentStage,
        to: source.targetStage,
        updatedBy: 'n8n workflow'
      }
    }
  }
];

const source = $('Build orchestration payloads').first().json;
let matches = [];
let matchSource = 'Reviewer matching response unavailable';

try {
  const response = $('Match reviewers through Peerflow backend').first().json;
  matches = Array.isArray(response.matches) ? response.matches.slice(0, 3) : [];
  matchSource = response.source ?? matchSource;
} catch (error) {
  matchSource = String(error.message ?? error);
}

const matchLines = matches.length
  ? matches.map((match, index) => String(index + 1) + '. ' + match.name + ' - ' + match.fit + '% fit - ' + match.institution + ' - ' + match.speciality)
  : ['No reviewer matches returned.'];

return [
  {
    json: {
      ...source,
      reviewerMatching: {
        source: matchSource,
        matches
      },
      attioTaskPayload: {
        data: {
          content: [
            'Peerflow reviewer outreach: ' + source.paper.title,
            'Paper profile embedded: title + abstract + field',
            'Reviewer profiles embedded: expertise + institution + past review topics',
            'Matching method: Superlinked semantic matching, not keyword search',
            'Embedding model: all-MiniLM-L6-v2',
            'Rerank model: ms-marco-MiniLM-L-6-v2',
            'Stage: ' + source.targetStage,
            'Top reviewer matches:',
            ...matchLines,
            'Next step: contact top reviewer candidates and log response.'
          ].join('\n'),
          format: 'plaintext',
          deadline_at: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000).toISOString(),
          is_completed: false,
          assignees: [],
          linked_records: []
        }
      }
    }
  }
];
